use std::cmp::max;

struct AvlNode {
    key: i32,
    left: Option<Box<AvlNode>>,
    right: Option<Box<AvlNode>>,
    height: i32,
}

impl AvlNode {
    fn new(key: i32) -> Self {
        AvlNode { key, left: None, right: None, height: 1 }
    }
}

fn height(node: &Option<Box<AvlNode>>) -> i32 {
    match node {
        Some(n) => n.height,
        None => 0,
    }
}

fn update_height(node: &mut AvlNode) {
    node.height = 1 + max(height(&node.left), height(&node.right));
}

fn balance_factor(node: &AvlNode) -> i32 {
    height(&node.left) - height(&node.right)
}

fn rotate_right(mut y: Box<AvlNode>) -> Box<AvlNode> {
    let mut x = y.left.take().unwrap();
    y.left = x.right.take();
    update_height(&mut y);
    x.right = Some(y);
    update_height(&mut x);
    x
}

fn rotate_left(mut x: Box<AvlNode>) -> Box<AvlNode> {
    let mut y = x.right.take().unwrap();
    x.right = y.left.take();
    update_height(&mut x);
    y.left = Some(x);
    update_height(&mut y);
    y
}

fn insert(node: Option<Box<AvlNode>>, key: i32) -> Box<AvlNode> {
    let mut node = match node {
        None => return Box::new(AvlNode::new(key)),
        Some(n) => n,
    };

    if key < node.key {
        node.left = Some(insert(node.left.take(), key));
    } else if key > node.key {
        node.right = Some(insert(node.right.take(), key));
    } else {
        return node;
    }

    update_height(&mut node);
    let bf = balance_factor(&node);

    if bf > 1 {
        let left_key = node.left.as_ref().unwrap().key;
        if key < left_key {
            return rotate_right(node);
        } else {
            node.left = Some(rotate_left(node.left.take().unwrap()));
            return rotate_right(node);
        }
    }
    if bf < -1 {
        let right_key = node.right.as_ref().unwrap().key;
        if key > right_key {
            return rotate_left(node);
        } else {
            node.right = Some(rotate_right(node.right.take().unwrap()));
            return rotate_left(node);
        }
    }

    node
}

fn inorder(node: &Option<Box<AvlNode>>, result: &mut Vec<i32>) {
    if let Some(n) = node {
        inorder(&n.left, result);
        result.push(n.key);
        inorder(&n.right, result);
    }
}

pub fn avl_insert_inorder(arr: &[i32]) -> Vec<i32> {
    let mut root: Option<Box<AvlNode>> = None;
    for &val in arr {
        root = Some(insert(root, val));
    }
    let mut result = Vec::new();
    inorder(&root, &mut result);
    result
}

object AvlTree {

  private case class Node(key: Int, left: Node, right: Node, height: Int)

  private def nodeHeight(node: Node): Int = if (node == null) 0 else node.height

  private def updateHeight(node: Node): Node =
    node.copy(height = 1 + math.max(nodeHeight(node.left), nodeHeight(node.right)))

  private def balanceFactor(node: Node): Int = nodeHeight(node.left) - nodeHeight(node.right)

  private def rotateRight(y: Node): Node = {
    val x = y.left
    val t2 = x.right
    val newY = updateHeight(y.copy(left = t2))
    updateHeight(x.copy(right = newY))
  }

  private def rotateLeft(x: Node): Node = {
    val y = x.right
    val t2 = y.left
    val newX = updateHeight(x.copy(right = t2))
    updateHeight(y.copy(left = newX))
  }

  private def insert(node: Node, key: Int): Node = {
    if (node == null) return Node(key, null, null, 1)
    val updated = if (key < node.key) node.copy(left = insert(node.left, key))
    else if (key > node.key) node.copy(right = insert(node.right, key))
    else return node

    val balanced = updateHeight(updated)
    val bf = balanceFactor(balanced)

    if (bf > 1 && key < balanced.left.key) return rotateRight(balanced)
    if (bf < -1 && key > balanced.right.key) return rotateLeft(balanced)
    if (bf > 1 && key > balanced.left.key)
      return rotateRight(balanced.copy(left = rotateLeft(balanced.left)))
    if (bf < -1 && key < balanced.right.key)
      return rotateLeft(balanced.copy(right = rotateRight(balanced.right)))

    balanced
  }

  private def inorder(node: Node, result: scala.collection.mutable.ListBuffer[Int]): Unit = {
    if (node == null) return
    inorder(node.left, result)
    result += node.key
    inorder(node.right, result)
  }

  def avlInsertInorder(arr: Array[Int]): Array[Int] = {
    var root: Node = null
    for (v <- arr) root = insert(root, v)
    val result = scala.collection.mutable.ListBuffer[Int]()
    inorder(root, result)
    result.toArray
  }
}

class AvlNode {
    var key: Int
    var left: AvlNode?
    var right: AvlNode?
    var height: Int

    init(_ key: Int) {
        self.key = key
        self.left = nil
        self.right = nil
        self.height = 1
    }
}

func nodeHeight(_ node: AvlNode?) -> Int {
    return node?.height ?? 0
}

func updateHeight(_ node: AvlNode) {
    node.height = 1 + max(nodeHeight(node.left), nodeHeight(node.right))
}

func balanceFactor(_ node: AvlNode) -> Int {
    return nodeHeight(node.left) - nodeHeight(node.right)
}

func rotateRight(_ y: AvlNode) -> AvlNode {
    let x = y.left!
    let t2 = x.right
    x.right = y
    y.left = t2
    updateHeight(y)
    updateHeight(x)
    return x
}

func rotateLeft(_ x: AvlNode) -> AvlNode {
    let y = x.right!
    let t2 = y.left
    y.left = x
    x.right = t2
    updateHeight(x)
    updateHeight(y)
    return y
}

func insertNode(_ node: AvlNode?, _ key: Int) -> AvlNode {
    guard let node = node else { return AvlNode(key) }
    if key < node.key { node.left = insertNode(node.left, key) }
    else if key > node.key { node.right = insertNode(node.right, key) }
    else { return node }

    updateHeight(node)
    let bf = balanceFactor(node)

    if bf > 1 && key < node.left!.key { return rotateRight(node) }
    if bf < -1 && key > node.right!.key { return rotateLeft(node) }
    if bf > 1 && key > node.left!.key {
        node.left = rotateLeft(node.left!)
        return rotateRight(node)
    }
    if bf < -1 && key < node.right!.key {
        node.right = rotateRight(node.right!)
        return rotateLeft(node)
    }

    return node
}

func inorderTraversal(_ node: AvlNode?, _ result: inout [Int]) {
    guard let node = node else { return }
    inorderTraversal(node.left, &result)
    result.append(node.key)
    inorderTraversal(node.right, &result)
}

func avlInsertInorder(_ arr: [Int]) -> [Int] {
    var root: AvlNode? = nil
    for val in arr {
        root = insertNode(root, val)
    }
    var result: [Int] = []
    inorderTraversal(root, &result)
    return result
}

interface AvlNode {
    key: number;
    left: AvlNode | null;
    right: AvlNode | null;
    height: number;
}

function createNode(key: number): AvlNode {
    return { key, left: null, right: null, height: 1 };
}

function nodeHeight(node: AvlNode | null): number {
    return node ? node.height : 0;
}

function updateHeight(node: AvlNode): void {
    node.height = 1 + Math.max(nodeHeight(node.left), nodeHeight(node.right));
}

function balanceFactor(node: AvlNode): number {
    return nodeHeight(node.left) - nodeHeight(node.right);
}

function rotateRight(y: AvlNode): AvlNode {
    const x = y.left!;
    const t2 = x.right;
    x.right = y;
    y.left = t2;
    updateHeight(y);
    updateHeight(x);
    return x;
}

function rotateLeft(x: AvlNode): AvlNode {
    const y = x.right!;
    const t2 = y.left;
    y.left = x;
    x.right = t2;
    updateHeight(x);
    updateHeight(y);
    return y;
}

function insertNode(node: AvlNode | null, key: number): AvlNode {
    if (!node) return createNode(key);
    if (key < node.key) node.left = insertNode(node.left, key);
    else if (key > node.key) node.right = insertNode(node.right, key);
    else return node;

    updateHeight(node);
    const bf = balanceFactor(node);

    if (bf > 1 && key < node.left!.key) return rotateRight(node);
    if (bf < -1 && key > node.right!.key) return rotateLeft(node);
    if (bf > 1 && key > node.left!.key) {
        node.left = rotateLeft(node.left!);
        return rotateRight(node);
    }
    if (bf < -1 && key < node.right!.key) {
        node.right = rotateRight(node.right!);
        return rotateLeft(node);
    }

    return node;
}

function inorderTraversal(node: AvlNode | null, result: number[]): void {
    if (!node) return;
    inorderTraversal(node.left, result);
    result.push(node.key);
    inorderTraversal(node.right, result);
}

export function avlInsertInorder(arr: number[]): number[] {
    let root: AvlNode | null = null;
    for (const val of arr) {
        root = insertNode(root, val);
    }
    const result: number[] = [];
    inorderTraversal(root, result);
    return result;
}
